// <!-- agent-rails:generated -->
// Project-local OpenCode request hook. Generated by `agent-rails opencode install`.

import { spawn } from "node:child_process"
import { mkdtemp, readFile, rm } from "node:fs/promises"
import { tmpdir } from "node:os"
import { join } from "node:path"
import { createInterface } from "node:readline"

const CONFIG = __AGENT_RAILS_CONFIG__
const TEXT_KEYS = new Set(["text", "content", "output", "result", "error", "title", "summary"])

function positiveInteger(value, fallback) {
  const parsed = Number(value)
  return Number.isFinite(parsed) && parsed > 0 ? Math.floor(parsed) : fallback
}

function extractText(value, output = []) {
  if (typeof value === "string") {
    output.push(value)
    return output
  }
  if (Array.isArray(value)) {
    for (const item of value) extractText(item, output)
    return output
  }
  if (!value || typeof value !== "object") return output

  for (const [key, child] of Object.entries(value)) {
    if (child && typeof child === "object") extractText(child, output)
    else if (TEXT_KEYS.has(key)) extractText(child, output)
  }
  return output
}

function messageText(message) {
  return extractText(message?.parts ?? message?.content ?? []).join("\n")
}

function latestUserGoal(messages, rememberedGoal) {
  if (rememberedGoal) return rememberedGoal
  for (let index = messages.length - 1; index >= 0; index -= 1) {
    const message = messages[index]
    if (message?.info?.role !== "user" && message?.role !== "user") continue
    const text = messageText(message).trim()
    if (text) return text.slice(0, 4000)
  }
  return "Continue the current OpenCode task"
}

function inputLimit(model) {
  const limit = model && model.limit ? model.limit : {}
  const direct = positiveInteger(limit.input, 0)
  if (direct) return direct
  const context = positiveInteger(limit.context, 0)
  const output = positiveInteger(limit.output, 0)
  return context ? Math.max(0, context - output) : 0
}

function runProcess(command, args, extraEnv = {}) {
  return new Promise((resolve, reject) => {
    const child = spawn(command, args, {
      cwd: CONFIG.project,
      env: { ...process.env, ...extraEnv },
      stdio: ["ignore", "pipe", "pipe"],
    })
    let stdout = ""
    let stderr = ""
    const timeout = setTimeout(() => {
      child.kill()
      reject(new Error(`${command} exceeded ${CONFIG.hookTimeoutMs}ms`))
    }, CONFIG.hookTimeoutMs)
    child.stdout.on("data", (chunk) => { stdout += String(chunk) })
    child.stderr.on("data", (chunk) => { stderr += String(chunk) })
    child.on("error", (error) => {
      clearTimeout(timeout)
      reject(error)
    })
    child.on("close", (code) => {
      clearTimeout(timeout)
      if (code === 0) resolve({ stdout, stderr })
      else reject(new Error(`${command} exited ${code}: ${stderr || stdout}`))
    })
  })
}

class ContextAssembler {
  constructor() {
    this.child = null
    this.pending = new Map()
    this.nextID = 1
  }

  start() {
    if (this.child) return
    const args = [
      CONFIG.assembler,
      "--serve",
      "--tokenizer", CONFIG.tokenizer,
      "--chars-per-token", String(CONFIG.charsPerToken),
      "--tiktoken-encoding", CONFIG.tiktokenEncoding,
    ]
    if (CONFIG.tokenizerCommand) args.push("--tokenizer-command", CONFIG.tokenizerCommand)
    if (CONFIG.tokenizerPath) args.push("--tokenizer-path", CONFIG.tokenizerPath)

    this.child = spawn("python3", args, {
      cwd: CONFIG.project,
      env: process.env,
      stdio: ["pipe", "pipe", "pipe"],
    })
    const lines = createInterface({ input: this.child.stdout })
    lines.on("line", (line) => {
      let response
      try {
        response = JSON.parse(line)
      } catch (error) {
        this.failAll(error)
        return
      }
      const pending = this.pending.get(response.id)
      if (!pending) return
      this.pending.delete(response.id)
      clearTimeout(pending.timeout)
      if (response.error) pending.reject(new Error(response.error))
      else pending.resolve(response)
    })
    this.child.on("error", (error) => this.failAll(error))
    this.child.on("close", (code) => {
      this.failAll(new Error(`Agent Rails context assembler exited ${code}`))
      this.child = null
    })
  }

  failAll(error) {
    for (const pending of this.pending.values()) {
      clearTimeout(pending.timeout)
      pending.reject(error)
    }
    this.pending.clear()
  }

  request(payload) {
    this.start()
    const id = String(this.nextID++)
    return new Promise((resolve, reject) => {
      const timeout = setTimeout(() => {
        this.pending.delete(id)
        reject(new Error(`Agent Rails context assembler exceeded ${CONFIG.hookTimeoutMs}ms`))
      }, CONFIG.hookTimeoutMs)
      this.pending.set(id, { resolve, reject, timeout })
      this.child.stdin.write(`${JSON.stringify({ id, ...payload })}\n`, (error) => {
        if (!error) return
        clearTimeout(timeout)
        this.pending.delete(id)
        reject(error)
      })
    })
  }

  stop() {
    if (this.child) this.child.kill()
    this.child = null
  }
}

async function generateRawPack(goal, modelName) {
  const directory = await mkdtemp(join(tmpdir(), "agent-rails-opencode-"))
  const output = join(directory, "raw-pack.md")
  try {
    await runProcess(CONFIG.bin, [
      "pack",
      "--project", CONFIG.project,
      "--profile", CONFIG.profile,
      "--model", modelName,
      "--output", output,
      goal,
    ], { AGENT_RAILS_CANDIDATE_OUTPUT: "1" })
    return await readFile(output, "utf8")
  } finally {
    await rm(directory, { recursive: true, force: true })
  }
}

async function generateCharFallbackPack(goal, modelName, budgetTokens) {
  const directory = await mkdtemp(join(tmpdir(), "agent-rails-opencode-"))
  const output = join(directory, "fallback-pack.md")
  try {
    await runProcess(CONFIG.bin, [
      "pack",
      "--project", CONFIG.project,
      "--profile", CONFIG.profile,
      "--model", modelName,
      "--output", output,
      "--token-budget", String(budgetTokens),
      "--tokenizer", "char",
      goal,
    ])
    return await readFile(output, "utf8")
  } finally {
    await rm(directory, { recursive: true, force: true })
  }
}

export const AgentRails = async ({ client }) => {
  const assembler = new ContextAssembler()
  const sessionStates = new Map()

  const log = async (level, message, extra = {}) => {
    try {
      await client.app.log({
        body: { service: "agent-rails", level, message, extra },
      })
    } catch {
      // Logging must never block a model request.
    }
  }

  return {
    "chat.message": async (input, output) => {
      const goal = extractText(output?.parts ?? output?.message ?? []).join("\n").trim()
      if (goal) {
        sessionStates.set(input.sessionID, {
          goal: goal.slice(0, 4000),
          rawPack: null,
          pack: null,
          usedTokens: 0,
          modelName: null,
        })
      }
    },

    "experimental.chat.system.transform": async (input, output) => {
      let messages = []
      try {
        const response = await client.session.messages({ path: { id: input.sessionID } })
        messages = Array.isArray(response?.data) ? response.data : []
      } catch (error) {
        await log("warn", "Unable to read OpenCode session messages", { error: String(error) })
      }

      const existingContext = [
        ...(Array.isArray(output.system) ? output.system : []),
        ...messages.map(messageText),
      ].join("\n")

      let occupiedTokens
      try {
        occupiedTokens = (await assembler.request({ action: "count", text: existingContext })).tokens
      } catch (error) {
        occupiedTokens = Math.ceil(existingContext.length / CONFIG.charsPerToken)
        await log("warn", "Tokenizer service unavailable; using character estimate", { error: String(error) })
      }

      const ceiling = inputLimit(input.model)
      const effectiveCeiling = ceiling || (occupiedTokens + CONFIG.maxPackTokens + CONFIG.reserveTokens)
      const proportionalBudget = Math.floor(effectiveCeiling * CONFIG.contextPercent / 100)
      const safetyReserve = Math.max(
        CONFIG.reserveTokens,
        Math.floor(effectiveCeiling * CONFIG.reservePercent / 100),
      )
      const available = Math.max(0, effectiveCeiling - occupiedTokens - safetyReserve)
      const budgetTokens = Math.min(CONFIG.maxPackTokens, proportionalBudget, available)

      if (budgetTokens < CONFIG.minPackTokens) {
        output.system.push(
          `AGENT RAILS: SKIPPED (reason=only ${available} input tokens remain after reserve)`,
        )
        await log("warn", "Skipped Agent Rails context because the remaining window is too small", {
          available,
          occupiedTokens,
          inputLimit: ceiling,
        })
        return
      }

      const remembered = sessionStates.get(input.sessionID)
      const goal = latestUserGoal(messages, remembered?.goal)
      const modelName = input.model?.id ?? input.model?.modelID ?? "generic"
      const state = remembered ?? { goal, rawPack: null, pack: null, usedTokens: 0, modelName }
      if (state.modelName !== modelName) {
        state.rawPack = null
        state.pack = null
        state.usedTokens = 0
        state.modelName = modelName
      }
      sessionStates.set(input.sessionID, state)

      let metadata = { tokenizer: "cached", used_tokens: state.usedTokens }
      if (!state.pack || state.usedTokens > budgetTokens) {
        if (!state.rawPack) {
          try {
            state.rawPack = await generateRawPack(goal, modelName)
          } catch (error) {
            output.system.push("AGENT RAILS: SKIPPED (reason=Task Pack generation failed)")
            await log("error", "Unable to generate Agent Rails candidate context", { error: String(error) })
            return
          }
        }
        try {
          const assembled = await assembler.request({
            action: "assemble",
            text: state.rawPack,
            budget_tokens: budgetTokens,
          })
          state.pack = assembled.content
          state.usedTokens = assembled.metadata.used_tokens
          metadata = assembled.metadata
        } catch (error) {
          try {
            state.pack = await generateCharFallbackPack(goal, modelName, budgetTokens)
          } catch (fallbackError) {
            output.system.push("AGENT RAILS: SKIPPED (reason=context assembly failed)")
            await log("error", "Unable to assemble Agent Rails context", {
              error: String(error),
              fallbackError: String(fallbackError),
            })
            return
          }
          state.usedTokens = Math.ceil(state.pack.length / CONFIG.charsPerToken)
          metadata = { tokenizer: "char-estimate", used_tokens: state.usedTokens }
          await log("warn", "Assembler failed; generated a char-budget fallback pack", { error: String(error) })
        }
      }

      output.system.push(`<!-- agent-rails:runtime -->\n${state.pack}`)
      await log("info", "Injected token-budgeted Agent Rails context", {
        budgetTokens,
        occupiedTokens,
        inputLimit: ceiling,
        tokenizer: metadata.tokenizer,
        usedTokens: metadata.used_tokens,
      })
    },

    dispose: async () => assembler.stop(),
  }
}
